customCSS:
.grimoire-theme-container { border: 2px solid var(--grimoire-border, #00e5ff); padding: 25px; background: var(--grimoire-bg, #121212); color: var(--grimoire-text, #00e5ff); font-family: 'Courier New', monospace; border-radius: 8px; box-shadow: 0 0 15px rgba(0,229,255,0.2); }
.grimoire-theme-container .header { text-align: center; border-bottom: 1px solid var(--grimoire-border, #00e5ff); padding-bottom: 15px; margin-bottom: 20px; }
.grimoire-theme-container .header-meta { font-size: 12px; letter-spacing: 2px; text-transform: uppercase; }
.grimoire-theme-container .headline { font-size: 36px; font-weight: bold; text-transform: uppercase; letter-spacing: 4px; margin: 10px 0; }
.grimoire-theme-container .sub-headline { font-size: 16px; font-style: italic; opacity: 0.8; }
.grimoire-theme-container .body { line-height: 1.8; font-size: 16px; text-align: justify; }
.grimoire-theme-container .drop-cap { font-size: 3em; float: left; line-height: 0.8; margin-right: 10px; font-weight: bold; text-shadow: 0 0 8px var(--grimoire-text, #00e5ff); }
.grimoire-theme-container .ritual-box { margin: 25px 0; border: 1px dashed var(--grimoire-border, #00e5ff); padding: 15px 20px; background: rgba(0,229,255,0.05); text-align: center; }
.grimoire-theme-container .footer { text-align: center; border-top: 1px solid var(--grimoire-border, #00e5ff); margin-top: 30px; padding-top: 15px; font-size: 12px; letter-spacing: 2px; text-transform: uppercase; }
